def _utc_stamp() -> str:
    return datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")


def _backup_once(root: Path, rel_path: str) -> str | None:
    target = root / rel_path
    if not target.exists():
        return None
    backup_dir = root / ".patch_backup" / PATCH_ID
    backup_dir.mkdir(parents=True, exist_ok=True)
    backup = backup_dir / (rel_path.replace("/", "__") + f".before_{PATCH_ID}")
    if not backup.exists():
        backup.write_text(target.read_text(encoding="utf-8"), encoding="utf-8")
    return str(backup)


def _append_block_once(root: Path, rel_path: str, marker: str, block: str, create_if_missing: bool = True) -> dict[str, Any]:
    target = root / rel_path
    created = False
    if not target.exists():
        if not create_if_missing:
            return {"path": rel_path, "mutated": False, "created": False, "backup_path": None, "skipped_missing": True}
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text("", encoding="utf-8")
        created = True
    backup_path = _backup_once(root, rel_path)
    text = target.read_text(encoding="utf-8")
    mutated = False
    if marker not in text:
        if text and not text.endswith("\n"):
            text += "\n"
        text += "\n" + block.rstrip() + "\n"
        target.write_text(text, encoding="utf-8")
        mutated = True
    return {"path": rel_path, "mutated": mutated, "created": created, "backup_path": backup_path}


def _write_generated(root: Path) -> list[str]:
    written = []
    for rel_path, content in GENERATED_FILES.items():
        target = root / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(content, encoding="utf-8")
        written.append(rel_path)
    return written


def _mutate(root: Path) -> list[dict[str, Any]]:
    results: list[dict[str, Any]] = []
    production_py = root / "src/tradebot/production_hardening.py"
    production_pkg = root / "src/tradebot/production_hardening"
    if production_py.exists() or not production_pkg.exists():
        results.append(_append_block_once(root, "src/tradebot/production_hardening.py", SNAPSHOT_BLOCK_MARKER, SNAPSHOT_BLOCK, create_if_missing=True))
    if production_pkg.exists() and production_pkg.is_dir():
        results.append(_append_block_once(root, "src/tradebot/production_hardening/__init__.py", PACKAGE_INIT_BLOCK_MARKER, PACKAGE_INIT_BLOCK, create_if_missing=True))
    results.append(_append_block_once(root, "src/tradebot/operator_cockpit_v2_read_only.py", COCKPIT_BLOCK_MARKER, COCKPIT_BLOCK, create_if_missing=True))
    return results


def _compile_files(root: Path, files: list[str]) -> dict[str, str]:
    errors: dict[str, str] = {}
    for rel in files:
        if not rel.endswith(".py"):
            continue
        try:
            py_compile.compile(str(root / rel), doraise=True)
        except Exception as exc:
            errors[rel] = f"{type(exc).__name__}: {exc}"
    return errors


def main() -> int:
    parser = argparse.ArgumentParser(description=PATCH_NAME)
    parser.add_argument("--once-json", action="store_true")
    args = parser.parse_args()
    root = Path.cwd()
    written = _write_generated(root)
    mutations = _mutate(root)
    compile_targets = written + [str(m["path"]) for m in mutations if str(m.get("path", "")).endswith(".py")]
    compile_errors = _compile_files(root, compile_targets)
    report: dict[str, Any] = {
        **SAFETY_FALSE_FLAGS,
        "ok": not compile_errors,
        "applied": True,
        "patch_id": PATCH_ID,
        "patch_version": PATCH_VERSION,
        "patch_name": PATCH_NAME,
        "phase_61_h3_source_mutation_performed": True,
        "production_hardening_import_export_path_fixed_by_patch": True,
        "production_hardening_module_package_ambiguity_fixed_by_patch": True,
        "operator_cockpit_runtime_telemetry_added_by_patch": True,
        "legacy_api_drift_fix_performed_by_patch": True,
        "legacy_tests_skipped_by_patch": False,
        "mutated_files": [m["path"] for m in mutations],
        "mutation_results": mutations,
        "written_files": written,
        "compile_errors": compile_errors,
        "py_compile_ok": not compile_errors,
        "missing_files": [],
        "generated_at_utc": _utc_stamp(),
    }
    print(json.dumps(report, sort_keys=True) if args.once_json else json.dumps(report, indent=2, sort_keys=True))
    return 0 if report["ok"] else 1


if __name__ == "__main__":
    raise SystemExit(main())
